const numbersToWords=G=>{const x=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(G<0x14)return x[G];if(G<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](G/0xa)]+(G%0xa?'\x20'+x[G%0xa]:'');if(G<0x3e8){const U=Math['floor'](G/0x64),E=G%0x64;return(0x1===U?'εκατό':0x2===U?'διακόσια':0x3===U?'τριακόσια':0x4===U?'τετρακόσια':0x5===U?'πεντακόσια':0x6===U?'εξακόσια':0x7===U?'επτακόσια':0x8===U?'οκτακόσια':0x9===U?'εννιακόσια':'')+(E?'\x20'+numbersToWords(E):'');}return G<0xf4240?numbersToWords(Math['floor'](G/0x3e8))+'\x20χιλιάδες'+(G%0x3e8?'\x20'+numbersToWords(G%0x3e8):''):numbersToWords(Math['floor'](G/0xf4240))+'\x20εκατομμύρια'+(G%0xf4240?'\x20'+numbersToWords(G%0xf4240):'');},numberToText=(G,x='money')=>{const U=Math['floor'](G),E=Math['round'](0x64*(G-U));let B=numbersToWords(U),O=E>0x0?numbersToWords(E):'';switch(x){case'money':return O?B+'\x20ευρώ\x20και\x20'+O+'\x20λεπτά':B+'\x20ευρώ';case'time':return O?B+'\x20ώρες\x20και\x20'+O+'\x20λεπτά':B+'\x20ώρες';default:return O?B+'\x20και\x20'+O:''+B;}};